function ModelSorceryCard:OnSorceryCardOpenResp(pb)--打开装备卡界面返回
    local sorceryCardList = pb.sorceryCardList or {}                --奎特牌集合（激活的，大于 0 级的）
    local heroKeys = {}
    local cardList = {}
    for i, v in ipairs(sorceryCardList) do
        local sorceryCard = StructSorceryCard:New()
        sorceryCard:CreateByPb(v)
        local scRefId = sorceryCard.scRefId
        local heroId = sorceryCard.heroId
        if heroId and tonumber(heroId) > 0 then
            heroKeys[heroId] = scRefId
        end
        cardList[scRefId] = sorceryCard
    end
    self._heroKeys = heroKeys
    self._cardList = cardList
end

