function ModelSorceryCard:OnSorceryCardUpgradeReq(scRefId)--奎特牌激活/升级请求
    local pb = LProtoHelper.CreateProto(LProtoIds.SorceryCardUpgradeReq)
    pb.scRefId = scRefId                                            --奎特牌的refId
    SendMessage(pb, LProtoIds.SorceryCardUpgradeReq)
end
function ModelSorceryCard:OnSorceryCardUpgradeResp(pb)--奎特牌激活/升级返回
    local scRefId = pb.scRefId                                      --奎特牌的refId
    local level = pb.level                                          --激活/升级后等级
    local card = self._cardList[scRefId]

    local _level = card and card.level or 0
    if _level ~= level then
        local ref = self:GetSorceryCardRefByRefId(scRefId)
        local skillGroup = ref.skillGroup
        if _level == 0 and level > 0 then
            local nexSkillRef = self:GetSorceryCardSkillRef(skillGroup,level)
            GF.OpenWnd("UIJNUpLvPop",{newSkill = nexSkillRef.refId})
        else
            local oldSkillRef = self:GetSorceryCardSkillRef(skillGroup,_level)
            local nexSkillRef = self:GetSorceryCardSkillRef(skillGroup,level)
            if oldSkillRef.level ~= nexSkillRef.level then
                GF.OpenWnd("UIJNUpLvPop",{oldSkill = oldSkillRef.refId,newSkill = nexSkillRef.refId})
            end
        end
    end

    if card then
        card.level = level
    else
        card = {
            scRefId = scRefId,
            level = level
        }
    end
    self._cardList[scRefId] = card
end

