function ModelSorceryCard:VerifyLimitByCardIdAndHeroId(cardRefId,heroId)--检查穿戴限制
    local heroInfo = gModelHero:GetHeroServerDataById(heroId)
    local ref = self:GetSorceryCardRefByRefId(cardRefId)
    local equipLimit = ref.equipLimit
    local limitRef = gModelSorceryCard:GetSorceryCardUseLimitRefByRefId(equipLimit)
    if not limitRef or not heroInfo then return false end
    local suitRace,suitCareer,suitHeroInitQuality,suitGender,suitHero
    = limitRef.suitRace,limitRef.suitCareer,limitRef.suitHeroInitQuality,limitRef.suitGender,limitRef.suitHero
    local suitRaceList,suitCareerList,suitHeroInitQualityList,suitGenderList,suitHeroList
    if not string.isempty(suitRace) then
        local arr = string.split(suitRace,"|")
        suitRaceList = {}
        for i, v in ipairs(arr) do
            suitRaceList[tonumber(v)] = true
        end
    end
    if not string.isempty(suitCareer) then
        local arr = string.split(suitCareer,"|")
        suitCareerList = {}
        for i, v in ipairs(arr) do
            suitCareerList[tonumber(v)] = true
        end
    end
    if not string.isempty(suitHeroInitQuality) then
        local arr = string.split(suitHeroInitQuality,"|")
        suitHeroInitQualityList = {}
        for i, v in ipairs(arr) do
            suitHeroInitQualityList[tonumber(v)] = true
        end
    end
    if not string.isempty(suitGender) then
        local arr = string.split(suitGender,"|")
        suitGenderList = {}
        for i, v in ipairs(arr) do
            suitGenderList[tonumber(v)] = true
        end
    end
    if not string.isempty(suitHero) then
        local arr = string.split(suitHero,"|")
        suitHeroList = {}
        for i, v in ipairs(arr) do
            suitHeroList[tonumber(v)] = true
        end
    end

    local refId = heroInfo.refId
    local heroRef = gModelHero:GetHeroRef(refId)
    local raceType = heroRef.raceType
    local careerType = heroRef.careerType
    local quality = heroRef.quality
    local genderType = heroRef.genderType

    if ((not suitRaceList or suitRaceList[raceType])
            and (not suitCareerList or suitCareerList[careerType])
            and (not suitHeroInitQualityList or suitHeroInitQualityList[quality])
            and (not suitGenderList or suitGenderList[genderType]))
            or (suitHeroList and suitHeroList[refId])
    then
        return true
    end
    return false
end
function ModelSorceryCard:VerifyCardUpCost(refId,level)--检查卡牌升级
    local ref = self:GetSorceryCardRefByRefId(refId)
    if not ref then
        return false
    end
    local lvRef = self:GetSorceryCardUpgradeRef(refId,level)
    local associateItem = ref.associateItem
    local substitute = ref.substitute
    local icense = lvRef.icense
    local upCost = lvRef.upCost
    if upCost == -1 then--满级
        return false
    end
    local owtNum = 0
    local isUp = false  -- 是否可以升级
    local num = gModelItem:GetNumByRefId(associateItem)
    if num >= upCost then
        isUp = true
    else
        owtNum = owtNum + num
    end
    if not isUp and icense == 1 then
        local num = gModelItem:GetNumByRefId(substitute)
        owtNum = owtNum + num
        if owtNum >= upCost then
            isUp = true
        end
    end
    return isUp
end
function ModelSorceryCard:VerifyCollectTask(type)
    local list = self:GetCollectTaskRef()
    local ref = list[type]
    if not ref then return false end
    local questClassify = ref.questClassify
    return gModelQuest:IsHaveFinishTaskByType(questClassify)
end

