function ModelSorceryCard:GetSorceryCardRefByTheme(theme)
    local list
    if theme == 0 then
        list = {}
        for i, v in pairs(GameTable.SorceryCardRef) do
            table.insert(list,v)
        end
        table.sort(list,function (a,b)
            return a.refId < b.refId
        end)
    else
        local _themeList = self._themeList or {}
        list = _themeList[theme]
        if not list then
            list = {}
            for i, v in pairs(GameTable.SorceryCardRef) do
                if theme == v.theme then
                    table.insert(list,v)
                end
            end
            table.sort(list,function (a,b)
                return a.refId < b.refId
            end)
            _themeList[theme] = list
            self._themeList = _themeList
        end
    end
    return list
end
function ModelSorceryCard:GetSorceryCardRecomGroupRefByTheme(theme)
    local list
    if theme == 0 then
        list = {}
        for i, v in pairs(GameTable.SorceryCardRecomGroupRef) do
            table.insert(list,v)
        end
        table.sort(list,function (a,b)
            return a.sort < b.sort
        end)
    else
        local _themeRecomList = self._themeRecomList or {}
        list = _themeRecomList[theme]
        if not list then
            list = {}
            for i, v in pairs(GameTable.SorceryCardRecomGroupRef) do
                local themeArr = string.split(v.theme,",")
                local isTheme = false
                for j, k in ipairs(themeArr) do
                    if theme == tonumber(k)then
                        isTheme = true
                        break
                    end
                end
                if isTheme then
                    table.insert(list,v)
                end
            end
            table.sort(list,function (a,b)
                return a.sort < b.sort
            end)
            _themeRecomList[theme] = list
            self._themeRecomList = _themeRecomList
        end
    end
    return list
end
function ModelSorceryCard:InitSorceryCardUpgradeRef()
    local refList = {}
    for i, v in pairs(GameTable.SorceryCardUpgradeRef) do
        local cardType = v.cardType
        local level = v.level
        local list = refList[cardType] or {}
        list[level] = v
        refList[cardType] = list
    end
    self._SorceryCardUpgradeRef = refList
end
function ModelSorceryCard:GetSorceryCardUpgradeRef(refId,level)
    local refList = self._SorceryCardUpgradeRef or {}
    local list = refList[refId]
    if not list then return end
    return list[level]
end
function ModelSorceryCard:InitSorceryCardSkillRef()
    local skillMap = {}
    local warSkillMap = {}
    local refList = {}
    for i, v in pairs(GameTable.SorceryCardSkillRef) do
        local group = v.group
        local list = refList[group] or {}
        table.insert(list,v)
        refList[group] = list
        local skills = skillMap[v.skill]
        if not skills then
            skills = {}
            skillMap[v.skill] = skills
        end
        table.insert(skills,v)

        local warSkills = warSkillMap[v.warSkill]
        if not warSkills then
            warSkills = {}
            warSkillMap[v.warSkill] = warSkills
        end
        table.insert(warSkills,v)
    end
    for i, v in pairs(refList) do
        table.sort(v,function (a,b)
            return a.level < b.level
        end)
    end
    self._SorceryCardSkillRef = refList
    self._skillMap = skillMap
    self._warSkillMap = warSkillMap
end
function ModelSorceryCard:GetSorceryCardSkillRefByGroup(group)
