function ModelSorceryCard:GetSorceryCardSkillRef(group,lv)
    local list = self:GetSorceryCardSkillRefByGroup(group)
    if not list then return end
    local ref = list[1]
    local lock = false
    for i, v in ipairs(list) do
        if v.unlockLevel <= lv then
            ref = v
            lock = true
        end
    end
    return ref,lock
end
